import React from "react";

const Dashboard = () => {
  return (
    <div style={pageStyle}>
      <h1>💬 AI Therapist Chat</h1>
      <p>This is the chat page</p>
    </div>
  );
};

export default Dashboard;

const pageStyle = {
  height: "100vh",
  background: "#f4f4f4",
  display: "flex",
  flexDirection: "column",
  justifyContent: "center",
  alignItems: "center",
};
